import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { CommonModule } from '@angular/common';
import { NavbarComponent } from '../../components/navbar/navbar.component';
import { FooterComponent } from '../../components/footer/footer.component';

@Component({
  selector: 'app-book-detail',
  standalone: true,
  imports: [RouterLink, CommonModule, NavbarComponent, FooterComponent],
  templateUrl: './book-detail.component.html',
})
export class BookDetailComponent implements OnInit {
  activeTab: 'description' | 'details' | 'avis' = 'description';
  book: any = null;

  constructor(private route: ActivatedRoute) {}

  ngOnInit() {
    const id = this.route.snapshot.paramMap.get('id');
    this.book = {
      id,
      title: 'Mathématiques Terminale S',
      author: 'Seydou Traoré',
      price: 12000,
      condition: 'like_new',
      conditionLabel: 'Bon état',
      book_type: 'textbook',
      education_level: 'Terminale',
      subject: 'Mathématiques',
      description: 'Manuel complet de mathématiques pour la classe de Terminale S, conforme au programme sénégalais. Contient de nombreux exercices corrigés et des annales du baccalauréat.',
      isbn: '978-2-01-135467-3',
      images: [{ url: `https://picsum.photos/seed/detail${id}/600/800`, is_primary: true }],
      seller: { id: 1, first_name: 'Fatou', last_name: 'Seck', phone: '+221 77 123 45 67', address: 'Dakar, Sénégal', rating: 4.9, reviews: 98, books_sold: 67, member_since: 'septembre 2021' },
      rating: 4.7,
      reviews: 3,
      views: 892,
      favorites: 156,
      requests: 67,
      is_available: true,
      tags: ['Éducation', 'Français'],
    };
  }

  get conditionClass(): string {
    const map: Record<string, string> = { new: 'bg-green-100 text-green-700', like_new: 'bg-blue-100 text-blue-700', good: 'bg-amber-100 text-amber-700', fair: 'bg-gray-100 text-gray-600' };
    return map[this.book.condition] || 'bg-gray-100 text-gray-600';
  }

  openWhatsApp() {
    const msg = encodeURIComponent(`Bonjour, je suis intéressé par votre livre "${this.book.title}" sur Kittab.`);
    window.open(`https://wa.me/${this.book.seller.phone.replace(/\s/g,'')}?text=${msg}`, '_blank');
  }
}
